1979   // Store the result and return it at the end instead of exiting early, in case
1980   // allowExtraAnalysis is used to report multiple reasons for not vectorizing.
1981   bool Result = true;
1982 
1983   bool DoExtraAnalysis = ORE->allowExtraAnalysis(DEBUG_TYPE);
1984   // Check whether the loop-related control flow in the loop nest is expected by
1985   // vectorizer.
1986   if (!canVectorizeLoopNestCFG(TheLoop, UseVPlanNativePath)) {
1987     if (DoExtraAnalysis) {
1988       LLVM_DEBUG(dbgs() << "LV: legality check failed: loop nest");
1989       Result = false;
1990     } else {
1991       return false;
1992     }
1993   }
1994 
1995   // We need to have a loop header.
1996   LLVM_DEBUG(dbgs() << "LV: Found a loop: " << TheLoop->getHeader()->getName()
1997                     << '\n');
1998 
1999   // Specific checks for outer loops. We skip the remaining legal checks at this
2000   // point because they don't support outer loops.
2001   if (!TheLoop->isInnermost()) {
2002     assert(UseVPlanNativePath && "VPlan-native path is not enabled.");
2003 
2004     if (!canVectorizeOuterLoop()) {
2005       reportVectorizationFailure("Unsupported outer loop",
2006                                  "UnsupportedOuterLoop", ORE, TheLoop);
2007       // TODO: Implement DoExtraAnalysis when subsequent legal checks support
2008       // outer loops.
2009       return false;
2010     }
2011 
2012     LLVM_DEBUG(dbgs() << "LV: We can vectorize this outer loop!\n");
2013     return Result;
2014   }
2015 
2016   assert(TheLoop->isInnermost() && "Inner loop expected.");
2017   // Check if we can if-convert non-single-bb loops.
2018   unsigned NumBlocks = TheLoop->getNumBlocks();
2019   if (NumBlocks != 1 && !canVectorizeWithIfConvert()) {
2020     LLVM_DEBUG(dbgs() << "LV: Can't if-convert the loop.\n");
2021     if (DoExtraAnalysis)
2022       Result = false;
2023     else
2024       return false;
2025   }
2026 
2027   // Check if we can vectorize the instructions and CFG in this loop.
2028   if (!canVectorizeInstrs()) {
2029     LLVM_DEBUG(dbgs() << "LV: Can't vectorize the instructions or CFG\n");
2030     if (DoExtraAnalysis)
2031       Result = false;
2032     else
2033       return false;
2034   }
2035 
2036   if (isa<SCEVCouldNotCompute>(PSE.getBackedgeTakenCount())) {
2037     if (TheLoop->getExitingBlock()) {
2038       reportVectorizationFailure("Cannot vectorize uncountable loop",
2039                                  "UnsupportedUncountableLoop", ORE, TheLoop);
2040       if (DoExtraAnalysis)
2041         Result = false;
2042       else
2043         return false;
2044     } else {
2045       if (!isVectorizableEarlyExitLoop()) {
2046         assert(UncountableExitType == UncountableEarlyExitDetail::None &&
2047                "Must be false without vectorizable early-exit loop");
2048         if (DoExtraAnalysis)
2049           Result = false;
2050         else
2051           return false;
2052       }
2053     }
2054   }
2055 
2056   // Go over each instruction and look at memory deps.
2057   if (!canVectorizeMemory()) {
2058     LLVM_DEBUG(dbgs() << "LV: Can't vectorize due to memory conflicts\n");
2059     if (DoExtraAnalysis)
2060       Result = false;
2061     else
2062       return false;
2063   }
2064 
2065   // TODO: Remove this restriction once we're sure it's safe to do so.
2066   //       Handling stores to invariant addresses will be slightly different
2067   //       based on the vectorization style chosen. If we bail out to a scalar
2068   //       tail before executing any lane that would take the uncountable exit,
2069   //       then the store that occurs in the scalar loop would suffice.
2070   //
2071   //       If we instead handle the lane taking the uncountable exit within the
2072   //       vectorized loop, then we will have to ensure that we extract the
2073   //       last active lane at that point in the loop instead of the last lane
2074   //       of the vector before performing a scalar store.
2075   if (UncountableExitType == UncountableEarlyExitDetail::ReadWrite &&
2076       !LAI->getStoresToInvariantAddresses().empty()) {
2077     LLVM_DEBUG(dbgs() << "LV: Cannot vectorize early exit loops with stores to "
2078                          "loop-invariant addresses\n");
2079     reportVectorizationFailure("Cannot vectorize early exit loops with stores "
2080                                "to loop-invariant addresses",
2081                                "LoopInvariantStoresInEELoop", ORE, TheLoop);
2082     return false;
2083   }
2084 
2085   if (Result) {
2086     LLVM_DEBUG(dbgs() << "LV: We can vectorize this loop"
2087                       << (LAI->getRuntimePointerChecking()->Need
2088                               ? " (with a runtime bound check)"
2089                               : "")
2090                       << "!\n");
2091   }
2092 
2093   unsigned SCEVThreshold = VectorizeSCEVCheckThreshold;
2094   if (Hints->getForce() == LoopVectorizeHints::FK_Enabled)
2095     SCEVThreshold = PragmaVectorizeSCEVCheckThreshold;
2096 
2097   if (PSE.getPredicate().getComplexity() > SCEVThreshold) {
2098     LLVM_DEBUG(dbgs() << "LV: Vectorization not profitable "
2099                          "due to SCEVThreshold");
2100     reportVectorizationFailure("Too many SCEV checks needed",
2101         "Too many SCEV assumptions need to be made and checked at runtime",
2102         "TooManySCEVRunTimeChecks", ORE, TheLoop);
2103     if (DoExtraAnalysis)
2104       Result = false;
2105     else
2106       return false;
2107   }
2108 
2109   // Okay! We've done all the tests. If any have failed, return false. Otherwise
2110   // we can vectorize, and at this point we don't have any other mem analysis
2111   // which may limit our maximum vectorization factor, so just return true with
2112   // no restrictions.
2113   return Result;
2114 }
