2116 bool LoopVectorizationLegality::canFoldTailByMasking() const {
2117   // The only loops we can vectorize without a scalar epilogue, are loops with
2118   // a bottom-test and a single exiting block. We'd have to handle the fact
2119   // that not every instruction executes on the last iteration.  This will
2120   // require a lane mask which varies through the vector loop body.  (TODO)
2121   if (TheLoop->getExitingBlock() != TheLoop->getLoopLatch()) {
2122     LLVM_DEBUG(
2123         dbgs()
2124         << "LV: Cannot fold tail by masking. Requires a singe latch exit\n");
2125     return false;
2126   }
2127 
2128   LLVM_DEBUG(dbgs() << "LV: checking if tail can be folded by masking.\n");
2129 
2130   SmallPtrSet<const Value *, 8> ReductionLiveOuts;
2131 
2132   for (const auto &Reduction : getReductionVars())
2133     ReductionLiveOuts.insert(Reduction.second.getLoopExitInstr());
2134 
2135   for (const auto &Entry : getInductionVars()) {
2136     PHINode *OrigPhi = Entry.first;
2137     for (User *U : OrigPhi->users()) {
2138       auto *UI = cast<Instruction>(U);
2139       if (!TheLoop->contains(UI)) {
2140         LLVM_DEBUG(dbgs() << "LV: Cannot fold tail by masking, loop IV has an "
2141                              "outside user for "
2142                           << *UI << "\n");
2143         return false;
2144       }
2145     }
2146   }
2147 
2148   // The list of pointers that we can safely read and write to remains empty.
2149   SmallPtrSet<Value *, 8> SafePointers;
2150 
2151   // Check all blocks for predication, including those that ordinarily do not
2152   // need predication such as the header block.
2153   SmallPtrSet<const Instruction *, 8> TmpMaskedOp;
2154   for (BasicBlock *BB : TheLoop->blocks()) {
2155     if (!blockCanBePredicated(BB, SafePointers, TmpMaskedOp)) {
2156       LLVM_DEBUG(dbgs() << "LV: Cannot fold tail by masking.\n");
2157       return false;
2158     }
2159   }
2160 
2161   LLVM_DEBUG(dbgs() << "LV: can fold tail by masking.\n");
2162 
2163   return true;
2164 }
