2166 void LoopVectorizationLegality::prepareToFoldTailByMasking() {
2167   // The list of pointers that we can safely read and write to remains empty.
2168   SmallPtrSet<Value *, 8> SafePointers;
2169 
2170   // Mark all blocks for predication, including those that ordinarily do not
2171   // need predication such as the header block.
2172   for (BasicBlock *BB : TheLoop->blocks()) {
2173     [[maybe_unused]] bool R = blockCanBePredicated(BB, SafePointers, MaskedOp);
2174     assert(R && "Must be able to predicate block when tail-folding.");
