4406   //   ...
4407   //
4408   // vector.early.exit.check:
4409   //   EMIT vp<%first.lane> = first-active-lane vp<%combined>
4410   //   EMIT vp<%at.cond.0> = extract-lane vp<%first.lane>, vp<%cond.0>
4411   //   EMIT branch-on-cond vp<%at.cond.0>
4412   // Successor(s): vector.early.exit.0, vector.early.exit.check.0
4413   //
4414   // vector.early.exit.check.0:
4415   //   EMIT vp<%at.cond.1> = extract-lane vp<%first.lane>, vp<%cond.1>
4416   //   EMIT branch-on-cond vp<%at.cond.1>
4417   // Successor(s): vector.early.exit.1, vector.early.exit.2
4418   VPBasicBlock *CurrentBB = DispatchVPBB;
